import React, { useEffect, useState } from 'react';
import { anomalyService } from '../api/dashboardServices';
import '../styles/ecoflow-3d-theme.css';

function AnomalyDetection() {
  const [loading, setLoading] = useState(true);
  const [anomalies, setAnomalies] = useState([]);
  const [selectedAnomaly, setSelectedAnomaly] = useState(null);
  const [reviewNotes, setReviewNotes] = useState('');

  useEffect(() => {
    loadAnomalies();
  }, []);

  const loadAnomalies = async () => {
    try {
      const data = await anomalyService.getAnomalies();
      setAnomalies(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleMarkReviewed = async () => {
    if (!selectedAnomaly) return;
    try {
      await anomalyService.markReviewed(selectedAnomaly.id, reviewNotes);
      loadAnomalies();
      setSelectedAnomaly(null);
      setReviewNotes('');
    } catch (err) {
      console.error(err);
    }
  };

  const getSeverityColor = (severity) => {
    switch (severity) {
      case 'critical': return '#ff2244';
      case 'high': return '#ff4444';
      case 'medium': return '#ffd93d';
      case 'low': return '#38ef7d';
      default: return '#a0b0c0';
    }
  };

  const getSeverityBadge = (severity) => {
    switch (severity) {
      case 'critical': return 'critical';
      case 'high': return 'error';
      case 'medium': return 'warning';
      case 'low': return 'success';
      default: return 'info';
    }
  };

  return (
    <div className="page-header">
      <div>
        <h1 className="page-title">🔍 Anomaly Detection</h1>
        <p className="page-subtitle">Identify and manage system anomalies and irregular patterns</p>
      </div>

      <div className="page-content">
        {loading ? (
          <div className="spinner" style={{ margin: '40px auto' }}></div>
        ) : (
          <div className="grid grid-3">
            {/* Anomalies List */}
            <div style={{ gridColumn: '1 / 2' }}>
              <div className="card">
                <div className="card-header">
                  <div className="card-title">Detected Anomalies</div>
                  <div className="badge badge-info">{anomalies.length}</div>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  {anomalies.map((anomaly, idx) => (
                    <div
                      key={idx}
                      className="card interactive"
                      onClick={() => setSelectedAnomaly(anomaly)}
                      style={{
                        cursor: 'pointer',
                        borderColor: selectedAnomaly?.id === anomaly.id ? '#00ff88' : 'rgba(0, 255, 136, 0.1)',
                        borderLeftColor: getSeverityColor(anomaly.severity),
                        borderLeftWidth: '3px',
                        background: selectedAnomaly?.id === anomaly.id 
                          ? 'rgba(0, 255, 136, 0.1)' 
                          : 'rgba(0, 0, 0, 0.2)'
                      }}
                    >
                      <div style={{ display: 'flex', gap: '8px', alignItems: 'start' }}>
                        <div style={{ fontSize: '16px' }}>⚠️</div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontWeight: '600', fontSize: '13px' }}>
                            {anomaly.type}
                          </div>
                          <div style={{ fontSize: '11px', color: '#a0b0c0', marginTop: '2px' }}>
                            Bin #{anomaly.bin_id}
                          </div>
                          <div style={{ fontSize: '11px', color: '#a0b0c0', marginTop: '2px' }}>
                            {new Date(anomaly.detected_at).toLocaleTimeString()}
                          </div>
                        </div>
                        <span className={`badge badge-${getSeverityBadge(anomaly.severity)}`}>
                          {anomaly.severity.toUpperCase()}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Anomaly Details */}
            {selectedAnomaly && (
              <div style={{ gridColumn: '2 / 4' }}>
                <div className="card">
                  <div className="card-header">
                    <div>
                      <div className="card-title">Anomaly Analysis</div>
                      <div className="card-subtitle">ID: {selectedAnomaly.id}</div>
                    </div>
                    <button 
                      className="btn btn-secondary btn-sm"
                      onClick={() => setSelectedAnomaly(null)}
                    >
                      ✕
                    </button>
                  </div>

                  {/* Anomaly Info */}
                  <div className="grid grid-2">
                    <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase' }}>Type</div>
                      <div style={{ fontSize: '16px', fontWeight: '600', marginTop: '6px' }}>
                        {selectedAnomaly.type}
                      </div>
                    </div>

                    <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase' }}>Severity</div>
                      <div style={{ fontSize: '16px', fontWeight: '600', marginTop: '6px', color: getSeverityColor(selectedAnomaly.severity) }}>
                        {selectedAnomaly.severity.toUpperCase()}
                      </div>
                    </div>

                    <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase' }}>Bin</div>
                      <div style={{ fontSize: '16px', fontWeight: '600', marginTop: '6px' }}>
                        #{selectedAnomaly.bin_id}
                      </div>
                    </div>

                    <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase' }}>Status</div>
                      <div style={{ fontSize: '16px', fontWeight: '600', marginTop: '6px' }}>
                        {selectedAnomaly.reviewed ? '✓ Reviewed' : '⏳ Pending'}
                      </div>
                    </div>
                  </div>

                  {/* Anomaly Description */}
                  <div style={{ marginTop: '16px', padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                    <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase', marginBottom: '8px' }}>Details</div>
                    <div style={{ fontSize: '13px', color: '#d0d8e8', lineHeight: '1.6' }}>
                      {selectedAnomaly.description || 'No additional details available'}
                    </div>
                  </div>

                  {/* Metrics */}
                  {selectedAnomaly.metrics && (
                    <div style={{ marginTop: '16px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase', marginBottom: '8px' }}>Anomaly Metrics</div>
                      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '8px' }}>
                        {Object.entries(selectedAnomaly.metrics).map(([key, value]) => (
                          <div key={key} style={{ padding: '8px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '6px', textAlign: 'center' }}>
                            <div style={{ fontSize: '11px', color: '#a0b0c0' }}>{key}</div>
                            <div style={{ fontSize: '16px', fontWeight: '600', marginTop: '4px' }}>{value}</div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Review Notes */}
                  {!selectedAnomaly.reviewed && (
                    <div style={{ marginTop: '16px' }}>
                      <div className="input-group">
                        <label className="input-label">Review Notes</label>
                        <textarea
                          className="input-field"
                          placeholder="Add your analysis or action taken..."
                          value={reviewNotes}
                          onChange={(e) => setReviewNotes(e.target.value)}
                          style={{ minHeight: '100px', fontFamily: 'inherit' }}
                        />
                      </div>
                      <button 
                        className="btn btn-accent" 
                        style={{ width: '100%', marginTop: '12px' }}
                        onClick={handleMarkReviewed}
                      >
                        ✓ Mark as Reviewed
                      </button>
                    </div>
                  )}

                  {selectedAnomaly.reviewed && (
                    <div style={{ marginTop: '16px', padding: '12px', background: 'rgba(56, 239, 125, 0.1)', borderRadius: '8px', border: '1px solid rgba(56, 239, 125, 0.3)' }}>
                      <div style={{ fontSize: '12px', color: '#38ef7d', fontWeight: '600' }}>✓ Already Reviewed</div>
                      {selectedAnomaly.review_notes && (
                        <div style={{ fontSize: '12px', color: '#a0b0c0', marginTop: '8px' }}>
                          {selectedAnomaly.review_notes}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default AnomalyDetection;
